function parseDuration(str) {
  if (typeof str !== 'string' || str.length === 0) {
    throw new Error(`parseDuration: invalid input: ${JSON.stringify(str)}`);
  }

  // Bare integer — treat as milliseconds
  if (/^\d+$/.test(str)) {
    return parseInt(str, 10);
  }

  // Unit table ordered so "ms" is tested before "m"
  const units = [
    ['ms', 1],
    ['s', 1000],
    ['m', 60000],
    ['h', 3600000],
    ['d', 86400000],
  ];

  let total = 0;
  let pos = 0;

  while (pos < str.length) {
    // Match leading digits
    let numEnd = pos;
    while (numEnd < str.length && str[numEnd] >= '0' && str[numEnd] <= '9') {
      numEnd++;
    }
    if (numEnd === pos) {
      throw new Error(`parseDuration: unparseable input at position ${pos}: ${JSON.stringify(str)}`);
    }
    const value = parseInt(str.slice(pos, numEnd), 10);
    pos = numEnd;

    // Match unit (ms before m)
    let matched = false;
    for (const [unit, multiplier] of units) {
      if (str.startsWith(unit, pos)) {
        total += value * multiplier;
        pos += unit.length;
        matched = true;
        break;
      }
    }
    if (!matched) {
      throw new Error(`parseDuration: unknown unit at position ${pos}: ${JSON.stringify(str)}`);
    }
  }

  return total;
}

